  } else {
    messageGenStatus = 'Failed';
    logMsg = `[${ts}] [AIGeneration] failed: all fields missing from AI response`;
  }

  // Placeholder detection (EC-035)
  const placeholderPattern = /\[(Company Name|Your Name|Name|First Name|Recipient|Industry|Product|Service|INSERT|FILL)[^\]]*\]/i;
  const allContent = Object.values(messages).join(' ');
