const garbageEmails = ['n/a', 'none', 'na', 'null', 'undefined', 'test', 'email', 'N/A'];

// LinkedIn URL validation (EC-013)
const linkedinPersonalRegex = /^https?:\/\/(www\.)?linkedin\.com\/in\/[\w\-%.]+\/?$/i;

// URL format validation (EC-023)
const urlRegex = /^https?:\/\/.+\..+$/;
const dangerousProtocols = ['javascript:', 'data:', 'file:', 'ftp:'];

// Sanitization function (EC-014, EC-037)
function sanitize(text) {
  if (!text || typeof text !== 'string') return '';
  // Strip HTML tags
  let clean = text.replace(/<[^>]*>/g, '');
  // Remove n8n expression patterns
  clean = clean.replace(/\{\{[^}]*\}\}/g, '[removed]');
  clean = clean.replace(/\$json\b/g, '[removed]');
  clean = clean.replace(/\$env\b/g, '[removed]');
  // Strip control characters
  clean = clean.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '');
  // Trim and limit length
  clean = clean.trim().substring(0, 2000);
  return clean;
}

// Normalize LinkedIn URL (per airtable_schema 7.3)
function normalizeLinkedIn(url) {
  if (!url) return '';
  let normalized = url.toLowerCase().trim();
  normalized = normalized.split('?')[0].split('#')[0];
  normalized = normalized.replace(/\/+$/, '');
  normalized = normalized.replace(/^http:\/\//, 'https://');
  if (normalized.includes('linkedin.com/in/') && !normalized.includes('www.')) {
    normalized = normalized.replace('linkedin.com', 'www.linkedin.com');
  }
  return normalized;
}

