  if (email) seenEmails.add(email);

  // Sanitize all text fields
  const fullName = sanitize(lead.name || lead.fullName || lead.full_name || lead.Name || '') || 'Unknown';
  const company = sanitize(lead.orgName || lead.company || lead.companyName || lead.company_name || lead.Company || '');
  const leadJobTitle = sanitize(lead.position || lead.jobTitle || lead.job_title || lead.title || lead.Title || '');
  const rawEmail = (lead.email || lead.Email || '').trim();
  const website = (lead.orgWebsite || lead.website || lead.companyWebsite || lead.company_website || lead.Website || '').trim();
  const linkedinRaw = (lead.linkedin || lead.linkedinUrl || lead.linkedin_url || lead.LinkedIn || '').trim();
