  const locationParts = [lead.city, lead.state, lead.country].filter(p => p && typeof p === 'string' && p.trim());
  const location = sanitize(locationParts.length > 0 ? locationParts.join(', ') : (lead.location || lead.Location || ''));
  const rawSize = lead.orgSize || lead.companySize || lead.company_size || '';
