  const hasEnrichmentSource = websiteValid || (linkedinStatus !== 'Missing' && linkedinStatus !== 'Invalid');
  const noContact = !emailValid && (linkedinStatus === 'Missing' || linkedinStatus === 'Invalid');

  processedLeads.push({
    fullName,
    email: rawEmail,
    emailValid,
    emailStatus,
    jobTitle: leadJobTitle,
    companyName: company,
    companyWebsite: website,
    websiteValid,
    websiteStatus,
    linkedinUrl: linkedinNormalized || linkedinRaw,
